class Solution:
    def isAdditiveNumber(self, num: str) -> bool:
        n = len(num)
        if n < 3:
            return False

        def check(idx, num1_str, num2_str):
            if idx == n:
                return True

            num1 = int(num1_str)
            num2 = int(num2_str)
            _sum = str(num1 + num2)

            if num[idx:].startswith(_sum):
                return check(idx + len(_sum), num2_str, _sum)
            else:
                return False

        for i in range(1, n):
            num1_str = num[0:i]
            if len(num1_str) > 1 and num1_str[0] == '0':
                continue

            for j in range(i + 1, n):
                num2_str = num[i:j]
                if len(num2_str) > 1 and num2_str[0] == '0':
                    continue

                if check(j, num1_str, num2_str):
                    return True

        return False
